sp_widget.client_script:
api.controller = function() {
    var c = this;
    c.loading = false;

    c.refresh = function() {
        if (c.loading) return;
        c.loading = true;
        c.server.get({ action: 'refresh' }).then(function(r) {
            c.data = r.data;
            c.loading = false;
        }, function() {
            c.loading = false;
        });
    };
};

sp_widget.css:
.sp-system-overview .page-header {
    border-bottom: 1px solid $border-tertiary;
    margin-bottom: 24px;
    padding-bottom: 16px;
}
.sp-system-overview .page-header h2 {
    color: $text-color;
    font-weight: 600;
    margin-top: 0;
}
.sp-system-overview .page-header .glyphicon {
    margin-right: 8px;
    color: $brand-primary;
}

/* Stat Tiles */
.sp-system-overview .sp-stat-tile {
    display: flex;
    align-items: center;
    padding: 18px;
    margin-bottom: 24px;
    border-radius: 4px;
    background: $background-primary;
    border: 1px solid $border-tertiary;
    box-shadow: 0 1px 4px rgba($text-color, 0.07);
}
.sp-system-overview .sp-stat-icon {
    width: 44px;
    height: 44px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-right: 14px;
    font-size: 18px;
}
.sp-system-overview .sp-stat-info .sp-stat-icon {
    background: $state-info-bg;
    color: $brand-info;
}
.sp-system-overview .sp-stat-success .sp-stat-icon {
    background: $state-success-bg;
    color: $brand-success;
}
.sp-system-overview .sp-stat-warning .sp-stat-icon {
    background: $state-warning-bg;
    color: $brand-warning;
}
.sp-system-overview .sp-stat-content {
    flex: 1;
}
.sp-system-overview .sp-stat-value {
    font-size: 26px;
    font-weight: 700;
    color: $text-color;
    line-height: 1.2;
}
.sp-system-overview .sp-stat-label {
    font-size: 12px;
    color: $text-muted;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

/* Panel */
.sp-system-overview .sp-panel {
    border: 1px solid $border-tertiary;
    box-shadow: 0 1px 4px rgba($text-color, 0.07);
    margin-bottom: 24px;
}
.sp-system-overview .sp-panel .panel-heading {
    background: $background-secondary;
    border-bottom: 1px solid $border-tertiary;
}
.sp-system-overview .sp-panel .panel-title {
    font-size: 15px;
    font-weight: 600;
    color: $text-color;
    margin: 0;
}
.sp-system-overview .sp-panel .panel-title .glyphicon {
    margin-right: 6px;
    color: $brand-primary;
}
.sp-system-overview .sp-panel .table th {
    color: $text-muted;
    font-weight: 600;
    font-size: 12px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    border-bottom: 2px solid $border-tertiary;
}
.sp-system-overview .sp-panel .table td {
    vertical-align: middle;
    color: $text-color;
}
.sp-system-overview .sp-panel .badge {
    background: $brand-primary;
}

sp_widget.script:
(function() {
    data.topColleges = [];
    data.topClubs = [];
    data.thisWeekEvents = [];
    data.recentRegistrations = [];
    data.totalStudents = 0;
    data.totalClubAdmins = 0;
    data.totalCollegeAdmins = 0;
    data.message = '';

    try {
        if (input && input.action === 'refresh') {
            // Same logic as initial load
        }

        // Top colleges by event count
        var collegeEventGa = new GlideAggregate('x_2097092_linq_event');
        collegeEventGa.addAggregate('COUNT');
        collegeEventGa.groupBy('college');
        collegeEventGa.orderByAggregate('COUNT', 'college');
        collegeEventGa.setLimit(10);
        collegeEventGa.query();
        while (collegeEventGa.next()) {
            var collegeSysId = collegeEventGa.getValue('college') + '';
            var collegeName = collegeEventGa.getDisplayValue('college') + '';
            var evCount = parseInt(collegeEventGa.getAggregate('COUNT'), 10) || 0;
            if (collegeName) {
                data.topColleges.push({
                    sys_id: collegeSysId,
                    name: collegeName,
                    event_count: evCount
                });
            }
        }

        // Top clubs by registration count
        var clubRegGa = new GlideAggregate('x_2097092_linq_registration');
        clubRegGa.addAggregate('COUNT');
        clubRegGa.groupBy('event.club');
        clubRegGa.orderByAggregate('COUNT', 'event.club');
        clubRegGa.setLimit(10);
        clubRegGa.query();
        while (clubRegGa.next()) {
            var clubSysId = clubRegGa.getValue('event.club') + '';
            var clubName = clubRegGa.getDisplayValue('event.club') + '';
            var regCount = parseInt(clubRegGa.getAggregate('COUNT'), 10) || 0;
            if (clubName) {
                data.topClubs.push({
                    sys_id: clubSysId,
                    name: clubName,
                    registration_count: regCount
                });
            }
        }

        // Events happening this week
        var now = new GlideDateTime();
        var weekEnd = new GlideDateTime();
        weekEnd.addDaysUTC(7);

        var weekEvGr = new GlideRecord('x_2097092_linq_event');
        weekEvGr.addQuery('event_date', '>=', now.getDate().getValue() + '');
        weekEvGr.addQuery('event_date', '<=', weekEnd.getDate().getValue() + '');
        weekEvGr.addQuery('status', 'IN', 'approved,live');
        weekEvGr.orderBy('event_date');
        weekEvGr.setLimit(20);
        weekEvGr.query();
        while (weekEvGr.next()) {
            data.thisWeekEvents.push({
                sys_id: weekEvGr.getUniqueValue(),
                title: weekEvGr.getValue('title') + '',
                club_name: weekEvGr.getDisplayValue('club') + '',
                college_name: weekEvGr.getDisplayValue('college') + '',
                event_date: weekEvGr.getDisplayValue('event_date') + '',
                venue: weekEvGr.getValue('venue') + '',
                status: weekEvGr.getValue('status') + ''
            });
        }

        // Recent registrations (last 20)
        var regGr = new GlideRecord('x_2097092_linq_registration');
        regGr.orderByDesc('sys_created_on');
        regGr.setLimit(20);
        regGr.query();
        while (regGr.next()) {
            data.recentRegistrations.push({
                sys_id: regGr.getUniqueValue(),
                student_name: regGr.getDisplayValue('student') + '',
                event_title: regGr.getDisplayValue('event') + '',
                registration_date: regGr.getDisplayValue('registration_date') + '',
                status: regGr.getValue('status') + ''
            });
        }

        // User statistics: total students (members with role 'member')
        var studentGa = new GlideAggregate('x_2097092_linq_club_membership');
        studentGa.addQuery('role', 'member');
        studentGa.addQuery('status', 'active');
        studentGa.addAggregate('COUNT', 'member');
        studentGa.groupBy('member');
        studentGa.setLimit(10000);
        studentGa.query();
        var studentCount = 0;
        while (studentGa.next()) {
            studentCount++;
        }
        data.totalStudents = studentCount;

        // Total club admins (president or vice_president)
        var adminGa = new GlideAggregate('x_2097092_linq_club_membership');
        adminGa.addQuery('role', 'IN', 'president,vice_president');
        adminGa.addQuery('status', 'active');
        adminGa.addAggregate('COUNT', 'member');
        adminGa.groupBy('member');
        adminGa.setLimit(10000);
        adminGa.query();
        var clubAdminCount = 0;
        while (adminGa.next()) {
            clubAdminCount++;
        }
        data.totalClubAdmins = clubAdminCount;

        // Total college admins (users with college_admin role)
        var collegeAdminGr = new GlideRecord('sys_user_has_role');
        collegeAdminGr.addQuery('role.name', 'x_2097092_linq.college_admin');
        collegeAdminGr.addQuery('state', 'active');
        collegeAdminGr.setLimit(1000);
        collegeAdminGr.query();
        data.totalCollegeAdmins = collegeAdminGr.getRowCount();

    } catch (e) {
        gs.error('linq-admin-system-overview error: ' + e.message);
        data.message = 'An error occurred loading system overview data.';
    }
})();
